import numpy as np, time
from scipy.linalg.lapack import dgeev

def mine(A):
    wr,wi,vl,vr,info = dgeev(A,0,1)
    idx = int(np.argmax(wr*wr+wi*wi))
    wij = wi[idx]
    if wij==0.0:
        return wr[idx], vr[:,idx]
    if wij>0:
        return wr[idx]+1j*wij, vr[:,idx]+1j*vr[:,idx+1]
    return wr[idx]+1j*wij, vr[:,idx-1]-1j*vr[:,idx]

def ref(A):
    w,v=np.linalg.eig(A); i=np.argmax(np.abs(w)); return w[i],v[:,i]

for size in [2,4,6,8,10]:
    # correctness
    for _ in range(200):
        A=np.random.normal(size=(size,size)).astype(np.float64)
        val,vec=mine(A)
        assert np.allclose(A@vec, val*vec), (size,val)
    def med(f):
        ds=[]
        for _ in range(200):
            A=np.random.normal(size=(size,size)).astype(np.float64)
            t=time.perf_counter(); f(A); ds.append(time.perf_counter()-t)
        return np.median(ds)
    print(size, 'mine',round(med(mine)*1e6,2),'ref',round(med(ref)*1e6,2))
"
